SELECT * FROM ( SELECT inner_q.project_id, inner_q.project_title, inner_q.project_describe, inner_q.created_at, inner_q.finish_date, inner_q.status, ROWNUM AS rn FROM ( SELECT p.project_id, p.project_title, p.project_describe, p.created_at, p.finish_date, c.default_describe AS status FROM project p LEFT JOIN common_code c ON p.status = c.common_id AND c.common_code = '0J'
p.project_title LIKE '%' || #{keyword} || '%'
ORDER BY p.created_at DESC, p.project_id DESC ) inner_q WHERE ROWNUM <= #{offset} + #{pageSize} ) WHERE rn > #{offset}

SELECT module_name
FROM module_mapping
WHERE project_id = #{projectId}
